  method: 'GET',
  hostname: '127.0.0.1',
  port: '3000',
  path: '/api/base/%7BbaseId%7D/workflow/%7BworkflowId%7D/action/%7BactionId%7D',
  headers: {
    Authorization: 'Bearer REPLACE_BEARER_TOKEN'
  }
};

